using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents remain queryable.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id no longer includes discriminator (was "Blog|1", now "1").
            // Preserve old format so existing documents remain accessible.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // EF Core 9: HasIndex on Cosmos entities now throws at startup.
        // Manage indexing via the Cosmos DB indexing policy instead.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

